# main_mock_agent.py
"""
RocketMQ ISR Agent MVP - 完全不依赖大模型版
- 使用 MockChain / RuleChain 模拟 LLM 输出
- 保留 FSM / Router / Tool
- 可以跑通 ISR 异常流程
"""

import json
from typing import List, Dict


# -----------------------------
# Mock / Rule Chain 定义
# -----------------------------

class MockChain:
    def __init__(self, name: str):
        self.name = name

    def invoke(self, context: Dict) -> Dict:
        if self.name == "CHECK_META":
            return {"abnormal_broker": "broker-b", "isr_status": "OUT_OF_SYNC", "lag": 18342,
                    "next_state": "CHECK_CONTROLLER_LOG", "confidence": 1.0}
        if self.name == "CHECK_CONTROLLER_LOG":
            return {"log": "remove broker-b from ISR, lag exceeds threshold", "decision": "controller_removed",
                    "next_state": "CHECK_BROKER_LOG", "confidence": 0.95}
        if self.name == "CHECK_BROKER_LOG":
            return {"log": "replication stalled, flush latency high", "suspect": "disk_io",
                    "next_state": "CHECK_RESOURCE", "confidence": 0.9}
        if self.name == "CHECK_RESOURCE":
            return {"disk_util": "98%", "await": "120ms", "root_cause_hint": "disk_io_bottleneck",
                    "next_state": "CONCLUDE", "confidence": 0.9}
        if self.name == "CONCLUDE":
            return {"root_cause": "broker-b 磁盘 IO 打满导致同步落后，被移出 ISR",
                    "impact": "Topic 副本降级，消费延迟升高",
                    "suggestion": ["扩容磁盘或迁移 broker", "检查刷盘策略", "评估 broker 替换"], "confidence": 1.0}
        return {}


# -----------------------------
# Router / FSM
# -----------------------------

def route(analysis: Dict, evidences: List[Dict]) -> MockChain:
    next_state = analysis.get("next_state", "CONCLUDE")
    return MockChain(next_state)


# -----------------------------
# End Chain
# -----------------------------

def end_chain(context: Dict) -> Dict:
    evidences = context.get("evidences", [])
    analysis = context.get("analysis", {})
    report = {
        "incident": "RocketMQ ISR 异常",
        "root_cause": analysis.get("root_cause", analysis.get("reason", "unknown")),
        "evidences": evidences,
        "suggested_action": analysis.get("suggestion", ["检查 broker 和 controller"]),
        "confidence": analysis.get("confidence", 0.0)
    }
    return report


# -----------------------------
# AgentExecutor - 流程跑通
# -----------------------------

def run_agent():
    evidences: List[Dict] = []

    # 初始化第一条 Chain
    current_chain = MockChain("CHECK_META")
    context = {}

    while True:
        analysis = current_chain.invoke(context)
        evidences.append({"state": current_chain.name, "output": analysis})

        if current_chain.name == "CONCLUDE":
            # 调用 End Chain
            final_report = end_chain({"analysis": analysis, "evidences": evidences})
            break

        # Router 决定下一条 Chain
        current_chain = route(analysis, evidences)

    print(json.dumps(final_report, indent=2, ensure_ascii=False))


# -----------------------------
# 运行示例
# -----------------------------

if __name__ == '__main__':
    run_agent()
